module alu #(
    parameter ADD = 6'b100000,
    parameter ADDU = 6'b100001,
    parameter SUB = 6'b100010,
    parameter SUBU = 6'b100011,
    parameter AND = 6'b100100,
    parameter OR = 6'b100101,
    parameter XOR = 6'b100110,
    parameter NOR = 6'b100111,
    parameter SLT = 6'b101010,
    parameter SLTU = 6'b101011,
    parameter SLL = 6'b000000,
    parameter SRL = 6'b000010,
    parameter SRA = 6'b000011,
    parameter SLLV = 6'b000100,
    parameter SRLV = 6'b000110,
    parameter SRAV = 6'b000111,
    parameter LUI = 6'b001111
) (
    input [31:0] a,
    input [31:0] b,
    input [5:0] aluc,
    output [31:0] r,
    output zero,
    output reg carry,
    output negative,
    output reg overflow,
    output flag
);
    reg [32:0] res;
    assign r = res[31:0];
    assign zero = &res[31:0];
    assign negative = res[31];
    assign flag = aluc == SLT | aluc == SLTU;
    always @(*) begin
        case (aluc)
            ADD: begin
                res = $signed(a) + $signed(b);
                carry = res[32];
                overflow = res[32] ^ res[31];
            end
            ADDU: begin
                res = a + b;
                carry = res[32];
                overflow = 0;
            end
            SUB: begin
                res = $signed(a) - $signed(b);
                carry = res[32];
                overflow = res[32] ^ res[31];
            end
            SUBU: begin
                res = a - b;
                carry = res[32];
                overflow = 0;
            end
            AND: begin
                res = {1'b0, a & b};
                carry = 0;
                overflow = 0;
            end
            OR: begin
                res = {1'b0, a | b};
                carry = 0;
                overflow = 0;
            end
            XOR: begin
                res = {1'b0, a ^ b};
                carry = 0;
                overflow = 0;
            end
            NOR: begin
                res = {1'b0, ~(a | b)};
                carry = 0;
                overflow = 0;
            end
            SLT: begin
                res = {1'b0, $signed(a) < $signed(b)};
                carry = 0;
                overflow = 0;
            end
            SLTU: begin
                res = {1'b0, a < b};
                carry = 0;
                overflow = 0;
            end
            SLL: begin
                res = {b[0], b[31:0] << b[4:0]};
                carry = 0;
                overflow = 0;
            end
            SRL: begin
                res = {b[0], b[31:0] >> b[4:0]};
                carry = 0;
                overflow = 0;
            end
            SRA: begin
                res = {b[0], $signed(b) >>> b[4:0]};
                carry = 0;
                overflow = 0;
            end
            SLLV: begin
                res = {b[0], b[31:0] << a[4:0]};
                carry = 0;
                overflow = 0;
            end
            SRLV: begin
                res = {b[0], b[31:0] >> a[4:0]};
                carry = 0;
                overflow = 0;
            end
            SRAV: begin
                res = {b[0], $signed(b) >>> a[4:0]};
                carry = 0;
                overflow = 0;
            end
            LUI: begin
                res = {b[15:0], 16'b0};
                carry = 0;
                overflow = 0;
            end
            default: begin
                res = 33'b0;
                carry = 0;
                overflow = 0;
            end
        endcase
    end
endmodule
